#include <bits/stdc++.h>
using namespace std;
const int maxn=3e6+5;
int son[maxn][26],cnt[maxn],idx;
void insert(string &s) {
	int p=0;
	for(auto c:s) {
		int u=c-'A';
		if(!son[p][u]) {
			son[p][u]=++idx;
		}
		p=son[p][u];
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	string s;
	while(cin>>s) {
		insert(s);
	}
	cout<<idx+1;
	return 0;
}
